head.b:skin:
:root {
  --font-body: 'Inter', system-ui, -apple-system, Segoe UI, Roboto, sans-serif;
  --content-max: 72rem;
  --text: #111827;
  --text-muted: #334155;
  --surface: #ffffff;
  --surface-alt: #f8fafc;
  --border: #cbd5e1;
  --focus-ring: #1d4ed8;
}
@media (prefers-color-scheme: dark) {
  :root {
    --text: #f8fafc;
    --text-muted: #cbd5e1;
    --surface: #0f172a;
    --surface-alt: #1e293b;
    --border: #475569;
    --focus-ring: #93c5fd;
  }
}
html, body { margin: 0; padding: 0; font-family: var(--font-body); color: var(--text); background: var(--surface); }
.site-header { min-height: 72px; display: flex; align-items: center; justify-content: space-between; max-width: var(--content-max); margin: 0 auto; padding: 0 1rem; gap: 0.75rem; }
.site-header__actions { display: inline-flex; align-items: center; gap: 0.5rem; }
.site-nav { max-width: var(--content-max); margin: 0 auto; padding: 0 1rem 0.75rem; }
.menu-list { margin: 0; padding: 0; list-style: none; display: none; gap: 0.75rem; }
.menu-list.is-open { display: flex; flex-direction: column; }
.menu-list a { color: var(--text); text-decoration: none; }
.hero { max-width: var(--content-max); margin: 0 auto; padding: 1.5rem 1rem 0; }
.hero__media { aspect-ratio: 16 / 9; border-radius: 14px; overflow: hidden; }
.hero__media img { width: 100%; height: 100%; object-fit: cover; display: block; }
.post-list { max-width: var(--content-max); margin: 1.5rem auto; padding: 0 1rem; }
.post-card { display: grid; grid-template-columns: 128px 1fr; gap: 1rem; align-items: start; margin-bottom: 1rem; }
.post-card__thumb { width: 128px; aspect-ratio: 4 / 3; overflow: hidden; border-radius: 8px; background: var(--surface-alt); }
.post-card__thumb img { width: 100%; height: 100%; object-fit: cover; display: block; }
.post-card p { color: var(--text-muted); }
.icon { width: 1rem; height: 1rem; display: inline-block; vertical-align: -0.15rem; }
.icon-button { border: 1px solid var(--border); background: transparent; color: var(--text); border-radius: 0.5rem; padding: 0.5rem; display: inline-flex; align-items: center; justify-content: center; cursor: pointer; }
.pagination { display: flex; align-items: center; justify-content: space-between; margin-top: 1.5rem; gap: 0.75rem; }
.pagination__meta { color: var(--text-muted); }
.search-drawer[hidden] { display: none !important; }
.search-drawer { position: fixed; inset: 0; background: rgba(2, 6, 23, 0.7); display: flex; align-items: center; justify-content: center; padding: 1rem; z-index: 10; }
.search-drawer__panel { width: min(36rem, 100%); background: var(--surface); color: var(--text); border: 1px solid var(--border); border-radius: 0.75rem; padding: 1rem; box-shadow: 0 24px 48px rgba(15, 23, 42, 0.25); }
.search-drawer__header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 1rem; }
.search-drawer__meta { color: var(--text-muted); margin-top: 0.5rem; }
a:focus-visible, button:focus-visible, input:focus-visible, select:focus-visible, textarea:focus-visible {
  outline: 3px solid var(--focus-ring);
  outline-offset: 2px;
  border-radius: 0.375rem;
}

body.script:
(function () {
  var menuToggle = document.getElementById('menu-toggle');
  var menu = document.getElementById('mobile-menu');
  var menuLinks = menu ? Array.prototype.slice.call(menu.querySelectorAll('a')) : [];
  var searchToggle = document.getElementById('search-toggle');
  var searchDrawer = document.getElementById('search-drawer');
  var searchClose = document.getElementById('search-close');
  var searchInput = document.getElementById('site-search');
  var lastFocusedTrigger = null;

  function isActivationKey(event) {
    return event.key === 'Enter' || event.key === ' ';
  }

  function openMenu() {
    if (!menu || !menuToggle) return;
    menu.classList.add('is-open');
    menuToggle.setAttribute('aria-expanded', 'true');
  }

  function closeMenu() {
    if (!menu || !menuToggle) return;
    menu.classList.remove('is-open');
    menuToggle.setAttribute('aria-expanded', 'false');
  }

  if (menuToggle) {
    menuToggle.addEventListener('click', function () {
      var expanded = menuToggle.getAttribute('aria-expanded') === 'true';
      if (expanded) {
        closeMenu();
      } else {
        openMenu();
        if (menuLinks.length) menuLinks[0].focus();
      }
    });
    menuToggle.addEventListener('keydown', function (event) {
      if (isActivationKey(event)) {
        event.preventDefault();
        menuToggle.click();
      }
    });
  }

  menuLinks.forEach(function (link, index) {
    link.addEventListener('keydown', function (event) {
      if (event.key === 'ArrowDown') {
        event.preventDefault();
        menuLinks[(index + 1) % menuLinks.length].focus();
      } else if (event.key === 'ArrowUp') {
        event.preventDefault();
        menuLinks[(index - 1 + menuLinks.length) % menuLinks.length].focus();
      } else if (event.key === 'Escape') {
        closeMenu();
        if (menuToggle) menuToggle.focus();
      } else if (isActivationKey(event)) {
        event.preventDefault();
        link.click();
      }
    });
  });

  function getFocusableElements(container) {
    return Array.prototype.slice.call(container.querySelectorAll('a, button, input, select, textarea, [tabindex]:not([tabindex="-1"])'))
      .filter(function (node) { return !node.hasAttribute('disabled') && node.getAttribute('aria-hidden') !== 'true'; });
  }

  function openSearch(trigger) {
    if (!searchDrawer || !searchToggle) return;
    lastFocusedTrigger = trigger || document.activeElement;
    searchDrawer.hidden = false;
    searchToggle.setAttribute('aria-expanded', 'true');
    if (searchInput) searchInput.focus();
  }

  function closeSearch() {
    if (!searchDrawer || !searchToggle) return;
    searchDrawer.hidden = true;
    searchToggle.setAttribute('aria-expanded', 'false');
    if (lastFocusedTrigger && typeof lastFocusedTrigger.focus === 'function') {
      lastFocusedTrigger.focus();
    }
  }

  if (searchToggle) {
    searchToggle.addEventListener('click', function () {
      openSearch(searchToggle);
    });
    searchToggle.addEventListener('keydown', function (event) {
      if (isActivationKey(event)) {
        event.preventDefault();
        openSearch(searchToggle);
      }
    });
  }

  if (searchClose) {
    searchClose.addEventListener('click', closeSearch);
    searchClose.addEventListener('keydown', function (event) {
      if (isActivationKey(event)) {
        event.preventDefault();
        closeSearch();
      }
    });
  }

  if (searchDrawer) {
    searchDrawer.addEventListener('keydown', function (event) {
      if (event.key === 'Escape') {
        event.preventDefault();
        closeSearch();
        return;
      }
      if (event.key !== 'Tab') return;
      var focusable = getFocusableElements(searchDrawer);
      if (!focusable.length) return;
      var first = focusable[0];
      var last = focusable[focusable.length - 1];
      if (event.shiftKey && document.activeElement === first) {
        event.preventDefault();
        last.focus();
      } else if (!event.shiftKey && document.activeElement === last) {
        event.preventDefault();
        first.focus();
      }
    });
    searchDrawer.addEventListener('click', function (event) {
      if (event.target === searchDrawer) {
        closeSearch();
      }
    });
  }
}());
